{
  "vulnerable": true,
  "cwe": "CWE-22",
  "location": "validatePath usage allows directory traversal",
  "explanation": "The prefix check does not prevent '../' sequences, enabling path traversal to access files outside the intended directory."
}

{
  "vulnerable": true,
  "cwe": "CWE-22",
  "location": "validatePath always returns 1, allowing path traversal",
  "explanation": "The program trusts user‑supplied filename without proper validation, enabling directory traversal attacks"
}

{
  "vulnerable": true,
  "cwe": "CWE-78",
  "location": "snprintf constructing command with userInput",
  "explanation": "User-controlled input is inserted into a shell command without proper sanitization, leading to command injection."
}

{
  "vulnerable": true,
  "cwe": "CWE-122",
  "location": "fileNames[255] = '\\0';",
  "explanation": "Writes a null byte past the allocated string buffer, causing a heap buffer overflow."
}

{
  "vulnerable": true,
  "cwe": "CWE-22",
  "location": "snprintf constructing file_name_buffer with user input",
  "explanation": "User-controlled filename is concatenated without validation, allowing directory traversal attacks"
}

{
  "vulnerable": true,
  "cwe": "CWE-78",
  "location": "command construction with strncpy/strncat before system()",
  "explanation": "User-controlled input is concatenated into a shell command without validation, leading to command injection."
}

{
  "vulnerable": true,
  "cwe": "CWE-78",
  "location": "system(sys) call",
  "explanation": "Insufficient input validation allows command injection despite filtering only ';', '|', and '&'"
}

{
  "vulnerable": true,
  "cwe": "CWE-78",
  "location": "snprintf command creation / system call",
  "explanation": "User-supplied input is concatenated into a command string without validation, leading to OS command injection."
}

{
  "vulnerable": true,
  "cwe": "CWE-78",
  "location": "strcat(sys, buff) builds command string",
  "explanation": "User-controlled input is concatenated into a command passed to system(), enabling command injection."
}

